import java.io.IOException;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        String safeUserInput = sanitizeInput(userInput);

        String output = "<html><body>User input: " + safeUserInput + "</body></html>";

        response.setContentType("text/html");
        response.getWriter().write(output);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization to prevent XSS attacks
        // Here, we are using Apache Commons Text library for escaping HTML special characters

        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
